REPLACE INTO `surat_pemberitahuans` (`id`, `nomor_surat`, `judul_indonesia`, `judul_inggris`, `kepada`, `isi_surat`, `penutup`, `usaha_id`, `status`, `tanggal_surat`, `tempat_surat`, `nama_penandatangan`, `jabatan_penandatangan`, `nip_penandatangan`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(1, 'a12121212', 'SURAT PEMBERITAHUAN DITERIMA MAGANG', 'NOTIFICATION LETTER OF INTERNSHIP ACCEPTED', 'Kepada Yth. 12121212121', '<p>Dengan hormat, Bersama surat ini, kami informasikan bahwa setelah melalui proses seleksi administrasi dan wawancara, berikut adalah daftar peserta yang dinyatakan diterima untuk melaksanakan Program Magang Hub Kemnaker di lingkungan PT Hexagon Karyatama Indonesia.</p>', '<p>Demikian pemberitahuan ini kami sampaikan. Atas perhatian dan kerja sama yang baik, kami ucapkan terima kasih.</p>', 2, 'draft', '2026-01-06', 'Bandung', '1212', '1212', '1221', '2026-01-06 01:14:23', '2026-01-06 01:14:23', NULL);
REPLACE INTO `surat_penyerahans` (`id`, `nomor_surat`, `tipe_surat`, `perihal`, `lampiran`, `tanggal_surat`, `tempat_surat`, `pihak_pertama_nama`, `pihak_pertama_jabatan`, `pihak_pertama_instansi`, `pihak_pertama_nip`, `pihak_kedua_nama`, `pihak_kedua_jabatan`, `pihak_kedua_instansi`, `pihak_kedua_nip`, `deskripsi_penyerahan`, `keterangan`, `status`, `usaha_id`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(1, '021.001/SPN/IT/PTHXGN/MM/YYYY', 'SPN', 'Penyerahan Akun Content Management System', '1', '2026-01-06', 'Cimahi', 'Endar Suhendar, M.Pd.', 'CTO PT Hexagon Karyatama Indonesia', 'PT Hexagon Karyatama Indonesia', NULL, 'BTH', 'BTH', 'BTH', '2121212', '<p>Pada hari ini, Tuesday, 06 January 2026, telah dilakukan penyerahan username dan akun aplikasi antara:</p>', '<p>Dengan ditandatanganinya berita acara ini, maka Pihak Kedua telah menerima akun tersebut dalam keadaan baik dan dapat menggunakannya untuk keperluan operasional sesuai dengan ketentuan yang berlaku. Demikian berita acara ini dibuat dengan sebenarnya dan ditandatangani oleh kedua belah pihak dalam rangkap dua untuk digunakan sebagaimana mestinya.</p>', 'draft', 2, '2026-01-06 00:21:18', '2026-01-06 00:21:18', NULL);
